class Queue:
    def __init__(self):
        self.stack1 = []
        self.stack2 = []

    # This function is an implementation of the enqueue operation performed on a queue.
    # It takes an element as an argument and adds it to the end of the queue.
    def enqueue(self, data):
        self.stack1.append(data)

    # This function is an implementation of the dequeue operation performed on a queue.
    # It removes and returns the element at the front of the queue.
    def dequeue(self):
        if not self.stack2:
            while self.stack1:
                self.stack2.append(self.stack1.pop())
        return self.stack2.pop()

    # This function checks if the queue is empty.
    def is_empty(self):
        return not bool(self.stack1 or self.stack2)

    # This function returns the size of the queue.
    def size(self):
        return len(self.stack1) + len(self.stack2)

# Example usage:
queue = Queue()
